// Parse and validate the AI agent response containing facts + SEO data
const response = items[0].json.output;

let data;
if (typeof response === 'string') {
  // Clean any markdown code blocks
  let cleaned = response.trim();
  if (cleaned.startsWith('```json') || cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  }
  data = JSON.parse(cleaned);
} else if (typeof response === 'object') {
  data = response;
} else {
  throw new Error('Unexpected response format from AI agent');
}

// Validate structure
if (!data.main_title || !data.facts || !Array.isArray(data.facts)) {
  throw new Error('Missing required fields in AI response');
}

// Validate we have exactly 5 facts
if (data.facts.length !== 5) {
  throw new Error(`Expected 5 facts, got ${data.facts.length}`);
}

// Validate each fact has required fields
data.facts.forEach((fact, idx) => {
  if (!fact.year || !fact.fact || !fact.car_model || !fact.image_prompt || !fact.catchy_title) {
    throw new Error(`Fact ${idx + 1} is missing required fields`);
  }
});

// Store SEO data for later use
const seoData = {
  main_title: data.main_title,
  meta_description: data.meta_description,
  keywords: data.keywords,
  geo_summary: data.geo_summary
};

// Return each fact as a separate item for image processing
return data.facts.map((fact, index) => ({
  json: {
    fact_number: index + 1,
    year: fact.year,
    catchy_title: fact.catchy_title,
    fact: fact.fact,
    car_model: fact.car_model,
    image_prompt: fact.image_prompt,
    // Include SEO data in each item so it's available later
    seo_data: seoData
  }
}));

