// Extract the base64 image from Stability AI response and prepare for WordPress
const base64Image = items[0].json.artifacts[0].base64;
const factData = items[0].json;

// Convert base64 to binary data
const binaryData = Buffer.from(base64Image, 'base64');
const filename = `car-fact-${factData.year}-${factData.fact_number}.png`;

return [
  {
    json: {
      fact_number: factData.fact_number,
      year: factData.year,
      catchy_title: factData.catchy_title,
      fact: factData.fact,
      car_model: factData.car_model,
      image_filename: filename,
      seo_data: factData.seo_data  // Pass SEO data through
    },
    binary: {
      image: {
        data: base64Image,
        mimeType: 'image/png',
        fileName: filename
      }
    }
  }
];

// Build the complete SEO/GEO optimized HTML content for WordPress
const allFactsData = items[0].json;
const todayDate = $('Get Current Date').item.json.today_date;

// Convert aggregated facts to array format
const sortedFacts = [];
for (let i = 1; i <= 5; i++) {
  if (allFactsData[`fact_${i}`]) {
    sortedFacts.push(allFactsData[`fact_${i}`]);
  }
}

// Get SEO data from the first fact (all have the same SEO data)
const seoData = sortedFacts[0].seo_data;

// Use AI-generated catchy main title
const postTitle = seoData.main_title;

// Build GEO-optimized introduction with structured data
let htmlContent = `<!-- GEO Summary for AI Search Engines: ${seoData.geo_summary} -->\n`;
htmlContent += `<div class="car-facts-intro" itemscope itemtype="https://schema.org/Article">\n`;
htmlContent += `<meta itemprop="headline" content="${postTitle}"/>\n`;
htmlContent += `<meta itemprop="description" content="${seoData.meta_description}"/>\n`;
htmlContent += `<meta itemprop="datePublished" content="${new Date().toISOString()}"/>\n`;
htmlContent += `<meta itemprop="keywords" content="${seoData.keywords.join(', ')}"/>\n`;
htmlContent += `<p><strong>🚗 On this day in automotive history</strong> — ${todayDate} — discover five game-changing moments that revolutionized the car industry. From legendary debuts to record-breaking achievements, these stories will change how you see automotive history.</p>\n`;
htmlContent += `</div>\n\n`;

// Table of Contents for SEO
htmlContent += `<div class="table-of-contents" style="background: #f8f9fa; padding: 20px; border-left: 4px solid #007bff; margin: 20px 0;">\n`;
htmlContent += `<h2>📋 Quick Navigation</h2>\n`;
htmlContent += `<ol>\n`;
sortedFacts.forEach((fact, idx) => {
  htmlContent += `<li><a href="#fact-${idx + 1}">${fact.catchy_title}</a></li>\n`;
});
htmlContent += `</ol>\n`;
htmlContent += `</div>\n\n`;

// Add each fact with catchy titles and structured data
sortedFacts.forEach((fact, idx) => {
  const imageUrl = fact.source_url;
  const imageId = fact.id;

  htmlContent += `<div class="car-fact-section" id="fact-${idx + 1}" itemscope itemtype="https://schema.org/NewsArticle">\n`;

  // Use catchy AI-generated title
  htmlContent += `<h2 itemprop="headline">🏆 ${fact.catchy_title}</h2>\n`;
  htmlContent += `<p class="fact-year" style="color: #666; font-style: italic; margin: 10px 0;"><strong>Year:</strong> ${fact.year} | <strong>Vehicle:</strong> ${fact.car_model}</p>\n`;

  if (imageUrl) {
    htmlContent += `<figure class="wp-block-image size-large" itemprop="image" itemscope itemtype="https://schema.org/ImageObject">\n`;
    htmlContent += `<img src="${imageUrl}" alt="${fact.car_model} from ${fact.year} - historic automotive moment" class="wp-image-${imageId}" style="max-width: 100%; height: auto;" itemprop="url"/>\n`;
    htmlContent += `<meta itemprop="width" content="1024"/>\n`;
    htmlContent += `<meta itemprop="height" content="1024"/>\n`;
    htmlContent += `<figcaption itemprop="caption">${fact.car_model} (${fact.year})</figcaption>\n`;
    htmlContent += `</figure>\n`;
  }

  htmlContent += `<div itemprop="articleBody">\n`;
  htmlContent += `<p>${fact.fact}</p>\n`;
  htmlContent += `</div>\n`;

  // Add "Why This Matters" section for GEO
  htmlContent += `<div class="impact-section" style="background: #fff3cd; padding: 15px; border-radius: 5px; margin: 15px 0;">\n`;
  htmlContent += `<p><strong>💡 Why This Matters:</strong> <em>This moment exemplifies how automotive innovation shaped modern transportation and influenced the industry for decades to come.</em></p>\n`;
  htmlContent += `</div>\n`;

  htmlContent += `</div>\n\n`;
});

// Add conclusion with internal linking suggestions
htmlContent += `<div class="car-facts-conclusion">\n`;
htmlContent += `<hr style="margin: 30px 0;"/>\n`;
htmlContent += `<h3>🎯 Key Takeaways</h3>\n`;
htmlContent += `<p>These ${sortedFacts.length} remarkable events from ${todayDate} demonstrate the continuous evolution of automotive technology and design. From the ${sortedFacts[0].year}s to the ${sortedFacts[sortedFacts.length-1].year}s, each innovation built upon the last, creating the sophisticated vehicles we enjoy today.</p>\n`;
htmlContent += `<p><strong>🔔 Don't miss tomorrow's automotive history!</strong> Subscribe to never miss another fascinating story from the world of cars. Share this with fellow car enthusiasts who appreciate automotive heritage!</p>\n`;
htmlContent += `</div>\n`;

// FAQ Section for SEO (Schema.org)
htmlContent += `<div class="faq-section" itemscope itemtype="https://schema.org/FAQPage" style="margin-top: 30px;">\n`;
htmlContent += `<h3>❓ Frequently Asked Questions</h3>\n`;
htmlContent += `<div itemscope itemprop="mainEntity" itemtype="https://schema.org/Question">\n`;
htmlContent += `<h4 itemprop="name">What significant automotive events happened on ${todayDate}?</h4>\n`;
htmlContent += `<div itemscope itemprop="acceptedAnswer" itemtype="https://schema.org/Answer">\n`;
htmlContent += `<p itemprop="text">On ${todayDate} throughout automotive history, ${sortedFacts.length} major events occurred, including groundbreaking launches, racing victories, and industry milestones spanning from ${sortedFacts[0].year} to ${sortedFacts[sortedFacts.length-1].year}.</p>\n`;
htmlContent += `</div></div>\n`;
htmlContent += `</div>\n`;

return [
  {
    json: {
      title: postTitle,
      content: htmlContent,
      excerpt: seoData.meta_description,
      featured_media_id: sortedFacts[0].id,
      all_facts: sortedFacts,
      seo_keywords: seoData.keywords.join(', '),
      meta_description: seoData.meta_description,
      geo_summary: seoData.geo_summary,
      generation_date: new Date().toISOString()
    }
  }
];
